import './ProductDetailsPage.css';
import { useParams, useNavigate } from 'react-router-dom';
import { useState, useEffect } from 'react';

function ProductDetailsPage() {
    const { id } = useParams();
    const navigate = useNavigate();
    const [product, setProduct] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetch(`https://dummyjson.com/products/${id}`)
            .then(res => res.json())
            .then(data => {
                setProduct(data);
                setLoading(false);
            });
    }, [id]);

    if (loading) return <div className="loading">Loading...</div>;

    return (
        <div className="product-details">
            <button className="product-details__back" onClick={() => navigate(-1)}>Go Back</button>
            <img className="product-details__image" src={product.thumbnail} alt={product.title} />
            <h2 className="product-details__title">{product.title}</h2>
            <p className="product-details__description">{product.description}</p>
            <p className="product-details__price">${product.price}</p>
            <p className="product-details__info">Rating: {product.rating}</p>
            <p className="product-details__info">Brand: {product.brand}</p>
            <p className="product-details__info">Category: {product.category}</p>
            <p className="product-details__info">Stock: {product.stock}</p>
            <p className="product-details__info">Status: {product.availabilityStatus}</p>
        </div>
    );
}

export default ProductDetailsPage;
